from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismImportProductNode(BaseNode):
    name = "Prism: Import Product"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("version_path", "string", widget_type="file")
        self.add_output("success", "bool")
        self.add_output("imported_node", "any")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        path = inputs.get('version_path') or ''
        if core is None or not path:
            self.log_error("Need PrismCore and version_path.")
            return {'success': False, 'imported_node': {}}
        try:
            result = None
            products = getattr(core, 'products', None)
            if products is not None:
                for attr in ('importProduct', 'importFile'):
                    if hasattr(products, attr):
                        result = getattr(products, attr)(path)
                        break
            app_plugin = getattr(core, 'appPlugin', None)
            if result is None and app_plugin is not None:
                for attr in ('importImages', 'importFile'):
                    if not hasattr(app_plugin, attr):
                        continue
                    fn = getattr(app_plugin, attr)
                    try:
                        result = fn(core, path)
                    except TypeError:
                        result = fn(path)
                    break
            if result is None:
                self.log_error("No importProduct/importImages method available.")
                return {'success': False, 'imported_node': {}}
            self.log_success(f"Imported product: {path}")
            await self.set_output('exec_out', True)
            return {'success': True, 'imported_node': result if result is not None else {}}
        except Exception as e:
            self.log_error(f"importProduct failed: {e}")
            return {'success': False, 'imported_node': {}}

def register_node():
    return PrismImportProductNode
